  go_to_book(id:any,pub:any){
    localStorage.setItem('user_book_id',id);
    localStorage.setItem('user_pub_id',pub);
    this.router.navigate(['/user/bookdetails'])

  }
  ApplyCoupon(logValue:any){
    // console.log(logValue.form.value.coupon_code);
    this.load=true;
    this.dash_data.applyCoupon(localStorage.getItem('u-id'), localStorage.getItem('user-type_user'), localStorage.getItem('remember_token'),logValue.form.value.coupon_code).subscribe(data=>{
      console.log(data);
      this.check_response=data;
      if(this.check_response.success==1){
      localStorage.setItem('book_Index',this.check_response.book_id);
      this.load=false;
      this.toastr.successToastr('Coupon Code has been applied successfully','');
      setTimeout(()=>{
        this.router.navigate(['/user/purchaselist']).then(()=>{
          location.reload();
        });
      },1000)
      }
      else if(this.check_response.success==2){
        this.load=false;
        this.toastr.errorToastr('Coupon code has already been used','')
      }
      else{
        this.load=false;
         this.toastr.errorToastr('Invalid coupon code','')
      }
    },error=>{
      this.load=false;
      this.toastr.errorToastr('Something went wrong! please try again later','')

    })
  }

  omit_special_char(e:any){

    var regex = new RegExp("^[a-zA-Z0-9 ]+$");
    var str = String.fromCharCode(!e.charCode ? e.which : e.charCode);
    if (regex.test(str)) {
        return true;
    }

    e.preventDefault();
    return false;
  }
