import { Component, OnInit } from '@angular/core';
import { UserlogoutService } from '../userlogout.service';
import { UsersidebarinfoService } from '../usersidebarinfo.service';
import { GlobalConstants } from '../globalvar/global';
import { Router } from '@angular/router';
@Component({
  selector: 'app-usersidebar',
  templateUrl: './usersidebar.component.html',
  styleUrls: ['./usersidebar.component.css',
  '../../assets/cssfiles/bootstrap.css',
  '../../assets/cssfiles/font-awesome.css',
  '../../assets/chosen/chosen.css',
  '../../assets/cssfiles/apps.css',
  '../../assets/cssfiles/res.css',
  '../../assets/cssfiles/apps_inner.css']
})
export class UsersidebarComponent implements OnInit {
 
  name:string='';
  email:string='';
  userdata:any;
  dashboard_show:any;
  dash_show="active";
  list_show:any;
  dashboard:any;
  list:any;
  history:any;
  history_show:any;
  notif:any;
  notif_show:any;
  dash:any;
  p_phone:string='';
  p_street:string='';
  p_city:string='';
  p_pin:string='';
  p_state:string='';
  p_country:string='';
  file!:any;
  profile:string='';
  report:any;
  constructor(private router:Router,private userinfo:UsersidebarinfoService, private userlogout:UserlogoutService) { }

  ngOnInit(): void {
    this.dash=GlobalConstants.routerURL+'/user/user_view'
    this.dashboard=GlobalConstants.routerURL+'/user/user_dashboard';
    this.history=GlobalConstants.routerURL+'/user/order_history';
    this.notif=GlobalConstants.routerURL+'/user/notifications';
    this.list=GlobalConstants.routerURL+'/user/purchaselist';
    if(window.location.href==this.dashboard)
     {this.dashboard_show="active"; this.dash_show=""}
    
    else if(window.location.href==this.list)
     {this.list_show="active";this.dashboard_show="";this.dash_show=""}
     else if(window.location.href==this.history)
     {this.history_show="active";this.dashboard_show="";this.dash_show=""}
     else if(window.location.href==this.notif)
     {this.notif_show="active";this.dashboard_show="";this.dash_show=""}
     else if(window.location.href==this.dash)
     {
       this.dash_show="active";this.dashboard_show="";
     }
    
    this.userinfo.get_info_user(localStorage.getItem('u-id'),localStorage.getItem('user-type_user'),localStorage.getItem('remember_token')).subscribe(data=>{//console.log(data)
    this.userdata=data;
    var obj=JSON.parse(this.userdata);
    this.name=obj.message[0].name;
    this.email=obj.message[0].email;
    this.p_phone=obj.message[0].phone;
    this.p_state=obj.message[0].state;
    this.p_city=obj.message[0].city
    this.p_street=obj.message[0].street;
    this.p_pin=obj.message[0].pincode;
    this.p_country=obj.message[0].country;
    this.profile=obj.message[0].image_url;
    console.log(this.profile)
     if(obj.success==0&&obj.message=='Logout')
     { this.userlogout.logout_user();}
    })
  }
  // make_active_db(){this.dashboard_show="active"}
  // make_active_d(){this.dash_show="active";this.dashboard_show="";}
  // make_active_hist(){this.history_show="active";this.dashboard_show="";}
  // make_active_notif(){this.notif_show="active";this.dashboard_show="";}
  // make_active_list(){this.list_show="active";this.dashboard_show="";}
  gotoedit(){//this.router.navigate(['publisher/edit']);
  }
  reload_window(){
    window.location.reload();
  }
}
